import{_ as t,o as i,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"SCFI / CCFI 運價指數","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-1_SCFI_CCFI_運價指數.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-1_SCFI_CCFI_運價指數.md"}'),e={name:"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-1_SCFI_CCFI_運價指數.md"};function o(n,a,d,h,s,c){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="scfi-ccfi-運價指數" tabindex="-1">SCFI / CCFI 運價指數 <a class="header-anchor" href="#scfi-ccfi-運價指數" aria-label="Permalink to &quot;SCFI / CCFI 運價指數&quot;">​</a></h1><h2 id="📊-計算方法" tabindex="-1">📊 計算方法 <a class="header-anchor" href="#📊-計算方法" aria-label="Permalink to &quot;📊 計算方法&quot;">​</a></h2><h3 id="scfi-上海出口貨櫃運價指數" tabindex="-1">SCFI（上海出口貨櫃運價指數） <a class="header-anchor" href="#scfi-上海出口貨櫃運價指數" aria-label="Permalink to &quot;SCFI（上海出口貨櫃運價指數）&quot;">​</a></h3><ul><li><strong>發布機構</strong>：上海航交所（Shanghai Shipping Exchange, SSE）</li><li><strong>數據收集</strong>：每週五從 15 家以上大型承運人、託貨人及貨代企業收集 15 條航線的即期報價</li><li><strong>運價組成</strong>：海運費 + 海事附加費（BAF/FAF、EBS、CAF、PSS、WRS、巴拿馬運河費等），不含兩端裝卸費（THC）及內陸運費</li><li><strong>加權方式</strong>：歐洲航線 61%、地中海航線 24%、美西航線 15%，加權平均</li><li><strong>基準期</strong>：2009 年 10 月 16 日 = 1,000 點</li><li><strong>計量單位</strong>：40 呎貨櫃（FEU），美東/美西以美元計價</li><li><strong>發布時間</strong>：每週六 15:00（北京時間）</li></ul><h3 id="ccfi-中國貨櫃運價指數" tabindex="-1">CCFI（中國貨櫃運價指數） <a class="header-anchor" href="#ccfi-中國貨櫃運價指數" aria-label="Permalink to &quot;CCFI（中國貨櫃運價指數）&quot;">​</a></h3><ul><li><strong>發布機構</strong>：上海航交所</li><li><strong>覆蓋範圍</strong>：12 條全球主要貿易航線，反映中國主要港口出口貨櫃成本</li><li><strong>最新數據（2026/5/8）</strong>：綜合指數 1,278.79（週增 0.7%）</li><li><strong>主要航線指數</strong>：歐洲 1,545.84、美西/美東 953.97/1,068.5、波斯灣/紅海 2,249.57</li></ul><hr><h2 id="📈-歷史走勢-2023–2026" tabindex="-1">📈 歷史走勢（2023–2026） <a class="header-anchor" href="#📈-歷史走勢-2023–2026" aria-label="Permalink to &quot;📈 歷史走勢（2023–2026）&quot;">​</a></h2><h3 id="_2023-年-疫情後回落" tabindex="-1">2023 年：疫情後回落 <a class="header-anchor" href="#_2023-年-疫情後回落" aria-label="Permalink to &quot;2023 年：疫情後回落&quot;">​</a></h3><ul><li>年初 SCFI 約 1,040 點，全年區間約 840–1,140 點</li><li>紅海危機前運價已大幅回調至疫情前水準</li></ul><h3 id="_2024-年-紅海危機推升" tabindex="-1">2024 年：紅海危機推升 <a class="header-anchor" href="#_2024-年-紅海危機推升" aria-label="Permalink to &quot;2024 年：紅海危機推升&quot;">​</a></h3><ul><li>1 月急升至 2,130 點（較 2022 年 12 月暴增 73%）</li><li>6–7 月創高至 3,438–3,650 點（紅海繞航好望角、中國出口前置）</li><li>全年區間約 1,200–4,200 點</li></ul><h3 id="_2025-年-回落至低位" tabindex="-1">2025 年：回落至低位 <a class="header-anchor" href="#_2025-年-回落至低位" aria-label="Permalink to &quot;2025 年：回落至低位&quot;">​</a></h3><ul><li>2 月 SCFI 自年初下跌 17%，3 月底較 1 月跌 36%</li><li>9 月跌至 2023 年 12 月以來的最低點</li><li>美西航線降至 $1,460/FEU，美東降至 $2,385/FEU</li></ul><h3 id="_2026-年-震盪回升" tabindex="-1">2026 年：震盪回升 <a class="header-anchor" href="#_2026-年-震盪回升" aria-label="Permalink to &quot;2026 年：震盪回升&quot;">​</a></h3><ul><li>1 月均價 1,499 點（月減 1.9%），2 月觸底至 1,251 點</li><li>3 月起回升，4/30 達 1,911 點（十個月來首次突破 1,900）</li><li>5/13 達 1,954 點（年增 45.28%）</li><li>TradingEconomics 預估 Q2 末至 2,001 點，12 個月後至 2,300 點</li></ul><h3 id="當前即期運價-2026-5" tabindex="-1">當前即期運價（2026/5） <a class="header-anchor" href="#當前即期運價-2026-5" aria-label="Permalink to &quot;當前即期運價（2026/5）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>航線</th><th>每 FEU 價格</th><th>週變動</th></tr></thead><tbody><tr><td>上海→洛杉磯</td><td>$3,062</td><td>+5%</td></tr><tr><td>上海→紐約</td><td>$3,721</td><td>+7%</td></tr><tr><td>上海→鹿特丹</td><td>$2,170</td><td>+2%</td></tr><tr><td>全球均價</td><td>~$2,150/40FT</td><td>穩定微升</td></tr></tbody></table><hr><h2 id="🔍-關鍵觀察" tabindex="-1">🔍 關鍵觀察 <a class="header-anchor" href="#🔍-關鍵觀察" aria-label="Permalink to &quot;🔍 關鍵觀察&quot;">​</a></h2><ol><li><strong>SCFI 對市場極度敏感</strong>：紅海危機、季節性需求、新增運力交付均能快速反映在指數上</li><li><strong>即期 vs 合約價差縮小</strong>：2026 年承運人透過停航、路線重組控制運力，合約價與即期價差距收窄</li><li><strong>2026 年結構性過剩</strong>：全球貨櫃船隊約 3,230 萬 TEU，訂單占活躍船隊 30%，運力增速（3.8%）超過需求增速（2.5%）</li><li><strong>繞航效應</strong>：紅海/蘇伊士封鎖使亞歐航線增加 10–15 天航行時間，有效吸收過剩運力</li></ol><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-13): SCFI 綜合指數 1,954.21</li><li>Shanghai Shipping Exchange (2026-05-08): CCFI 綜合指數 1,278.79</li><li>Drewry World Container Index (2026-05-07): WCI $2,286/40ft</li><li>iContainers (2026-05): 全球貨櫃運價預測與航線數據</li><li>Trading Economics (2026-05): SCFI 歷史走勢與預測</li></ol>',24)])])}const C=t(e,[["render",o]]);export{u as __pageData,C as default};
